1	/**
2	 * LayerInfinite MCP Server — enrichment/format-assist.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Assist-mode description formatting. Provides directional
5	 * guidance: recommends the best tool, warns on low performers,
6	 * handles tie-breaking when scores are close.
7	 * ══════════════════════════════════════════════════════════════
8	 */
9	
10	import type { ScoredAction } from '../types.js';
11	
12	const CLOSE_RACE_GAP = 5; // percentage points
13	
14	export interface AssistFormatContext {
15	  toolName: string;
16	  taskType: string;
17	  description: string;
18	  score: ScoredAction | null;
19	  rank: number | null;
20	  totalTools: number;
21	  bestScore: ScoredAction | null;
22	}
23	
24	/**
25	 * Format a tool description for Assist mode.
26	 * Includes ranking, comparisons, and warnings for low performers.
27	 */
28	export function formatAssistEnrichment(ctx: AssistFormatContext): string {
29	  const { description, toolName, taskType, score, rank, totalTools, bestScore } = ctx;
30	  const base = description;
31	
32	  // No historical data at all
33	  if (!score || score.sampleSize < 1) {
34	    return `${base}\n\nNo historical data available for this tool on "${taskType}" tasks. Consider testing it in a low-risk context first.`;
35	  }
36	
37	  const lines = [base, '', formatHistoricalContext(toolName, taskType, score)];
38	
39	  // Add ranking guidance
40	  if (rank && score.sampleSize >= 3) {
41	    lines.push(formatRankingGuidance(rank, totalTools, score, bestScore));
42	  }
43	
44	  // Add warning for low performers
45	  lines.push(formatWarning(score, totalTools));
46	
47	  return lines.filter(Boolean).join('\n');
48	}
49	
50	function formatHistoricalContext(
51	  toolName: string,
52	  taskType: string,
53	  score: ScoredAction,
54	): string {
55	  const { successRate, sampleSize, trendLabel } = score;
56	
57	  if (sampleSize < 3) {
58	    return `Historically for "${taskType}" tasks, ${toolName} has been used ${sampleSize} time${sampleSize === 1 ? '' : 's'} (insufficient data for reliability).`;
59	  }
60	
61	  const trendText = trendLabel ? ` ${formatTrendInline(trendLabel)}` : '';
62	  return `Historically for "${taskType}" tasks, ${toolName} has a ${successRate}% success rate across ${sampleSize} executions.${trendText}`;
63	}
64	
65	function formatRankingGuidance(
66	  rank: number,
67	  total: number,
68	  score: ScoredAction,
69	  bestScore: ScoredAction | null,
70	): string {
71	  if (rank === 1) {
72	    // Is this best by a clear margin?
73	    if (bestScore && bestScore.actionName !== score.actionName) {
74	      // Actually find the gap — bestScore is the overall best, but this tool IS rank 1
75	      // Check if there's a close second
76	      return '★ This is the recommended tool for this task.';
77	    }
78	    return '★ This is the recommended tool for this task.';
79	  }
80	
81	  if (bestScore && bestScore.actionName !== score.actionName) {
82	    const gap = bestScore.successRate - score.successRate;
83	    if (gap <= CLOSE_RACE_GAP) {
84	      return `Tied for best option — within ${gap}% of the top-ranked tool (${bestScore.actionName} at ${bestScore.successRate}%).`;
85	    }
86	  }
87	
88	  return `Ranked #${rank} of ${total}. ⚠ Consider the success history when choosing tools.`;
89	}
90	
91	function formatWarning(score: ScoredAction, total: number): string {
92	  const { successRate, sampleSize } = score;
93	
94	  // Only warn when we have enough data
95	  if (sampleSize < 5) return '';
96	
97	  if (successRate < 30) {
98	    return `⚠ WARNING: This tool has a critically low success rate (${successRate}%). Strongly consider alternatives.`;
99	  }
100	
101	  if (successRate < 50) {
102	    const altCount = total > 1 ? ` ${total - 1} alternative${total > 2 ? 's' : ''} available` : '';
103	    return `⚠ CAUTION: This tool fails more than half the time (${successRate}% success).${altCount ? `Consider using one of the${altCount}.` : ''}`;
104	  }
105	
106	  return '';
107	}
108	
109	function formatTrendInline(trendLabel: string): string {
110	  switch (trendLabel) {
111	    case 'strongly_improving': return 'and has been improving significantly';
112	    case 'improving': return 'and has been improving';
113	    case 'slightly_improving': return 'with a slight positive trend';
114	    case 'stable': return ''; // no trend text for stable
115	    case 'slightly_declining': return 'with a slight negative trend';
116	    case 'declining': return 'but has been declining';
117	    case 'sharply_declining': return 'but has been declining significantly';
118	    default: return '';
119	  }
120	}
121

1	/**
2	 * LayerInfinite MCP Server — enrichment/format-recommend.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Recommend-mode description formatting. Informational only —
5	 * provides historical success data with no directional guidance.
6	 * Appends enrichment as a single concatenated sentence.
7	 * ══════════════════════════════════════════════════════════════
8	 */
9	
10	import type { ScoredAction } from '../types.js';
11	
12	export function formatRecommendEnrichment(
13	  description: string,
14	  toolName: string,
15	  taskType: string,
16	  score: ScoredAction | null,
17	  rank: number | null,
18	): string {
19	  if (!score || score.sampleSize < 1) return description;
20	
21	  const { successRate, sampleSize, trendLabel } = score;
22	  const pct = Math.round(successRate * 100);
23	
24	  let enrichment: string;
25	  if (sampleSize < 3) {
26	    enrichment = `Insufficient historical data for ${toolName} on ${taskType} (${sampleSize} recorded outcomes).`;
27	  } else if (sampleSize < 10) {
28	    enrichment = `Historically, ${toolName} has resolved ${taskType} issues successfully ${pct}% of the time (limited data: ${sampleSize} outcomes).`;
29	  } else {
30	    enrichment = `Historically, ${toolName} has resolved ${taskType} issues successfully ${pct}% of the time (${sampleSize} recorded outcomes).`;
31	  }
32	
33	  if (trendLabel && sampleSize >= 10) {
34	    enrichment += ` Success rate is ${formatTrend(trendLabel)}.`;
35	  }
36	
37	  return `${description} ${enrichment}`;
38	}
39	
40	function formatTrend(trendLabel: string): string {
41	  switch (trendLabel) {
42	    case 'strongly_improving': return 'improving significantly';
43	    case 'improving': return 'improving';
44	    case 'slightly_improving': return 'showing a slight positive trend';
45	    case 'stable': return 'stable';
46	    case 'slightly_declining': return 'showing a slight decline';
47	    case 'declining': return 'declining';
48	    case 'sharply_declining': return 'declining significantly';
49	    default: return '';
50	  }
51	}
52

1	/**
2	 * LayerInfinite MCP Server — enrichment/score-fetcher.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Cache-aware score fetching from LI API. Uses in-memory LRU
5	 * with 5-min TTL to avoid blocking agents on every tools/list.
6	 * Cold-start safe: returns empty array when no scores available.
7	 * ══════════════════════════════════════════════════════════════
8	 */
9	
10	import type { LiApiClient } from '../rest-client.js';
11	import type { ScoredAction } from '../types.js';
12	import { logger } from '../logger.js';
13	
14	const log = logger.forTool('score-fetcher');
15	
16	const MAX_CACHE_SIZE = 1000;
17	const CACHE_TTL_MS = 5 * 60 * 1000; // 5 min
18	const FETCH_TIMEOUT_MS = 500;
19	
20	interface CacheEntry {
21	  scores: ScoredAction[];
22	  accessedAt: number;
23	}
24	
25	export class ScoreFetcher {
26	  private readonly cache = new Map<string, CacheEntry>();
27	
28	  constructor(private readonly liApi: LiApiClient) {}
29	
30	  /** Get scores for a task type. Returns empty array on cold start or timeout. */
31	  async getScores(
32	    taskType: string,
33	    customerId: string,
34	    agentId: string,
35	  ): Promise<ScoredAction[]> {
36	    const key = `${customerId}:${taskType}`;
37	    const cached = this.cache.get(key);
38	
39	    // Return cache hit if fresh
40	    if (cached && Date.now() - cached.accessedAt < CACHE_TTL_MS) {
41	      cached.accessedAt = Date.now();
42	      return cached.scores;
43	    }
44	
45	    // Fetch with tight timeout — never block the agent
46	    try {
47	      const scores = await this.fetchWithTimeout(taskType, customerId, agentId);
48	      this.setCache(key, scores);
49	      return scores;
50	    } catch (err) {
51	      log.warn('Score fetch failed, returning cached or empty', {
52	        taskType,
53	        error: err instanceof Error ? err.message : String(err),
54	      });
55	      // Return stale cache if available, otherwise empty
56	      return cached?.scores ?? [];
57	    }
58	  }
59	
60	  /** Clear the score cache. Useful on config changes. */
61	  clearCache(): void {
62	    this.cache.clear();
63	  }
64	
65	  /** Warm the cache proactively (called at startup or after training). */
66	  async warm(taskType: string, customerId: string, agentId: string): Promise<void> {
67	    try {
68	      const scores = await this.liApi.getScores(taskType, customerId, agentId);
69	      this.setCache(`${customerId}:${taskType}`, scores);
70	    } catch {
71	      // Warm is best-effort
72	    }
73	  }
74	
75	  get cacheSize(): number {
76	    return this.cache.size;
77	  }
78	
79	  private setCache(key: string, scores: ScoredAction[]): void {
80	    // Evict oldest entry if at capacity
81	    if (this.cache.size >= MAX_CACHE_SIZE) {
82	      let oldestKey = '';
83	      let oldestTime = Infinity;
84	      for (const [k, v] of this.cache) {
85	        if (v.accessedAt < oldestTime) {
86	          oldestTime = v.accessedAt;
87	          oldestKey = k;
88	        }
89	      }
90	      if (oldestKey) this.cache.delete(oldestKey);
